		function OnChangeValue()
{
	if (Ctrl("VALUE_BOOL"))
	{
		Ctrl("d_value"     ).SetXValue(Ctrl("VALUE_BOOL").GetXValue());
		Ctrl("d_value_text").SetXValue(Ctrl("VALUE_BOOL").GetXValue()=="0"?"NO/FALSO":"SI/VERDADERO");
	}
	if (Ctrl("VALUE_INT"))
	{  
		Ctrl("d_value"     ).SetXValue(Ctrl("VALUE_INT").GetXValue());
		Ctrl("d_value_text").SetXValue(Ctrl("VALUE_INT").GetXValue());
	}
	if (Ctrl("VALUE_DOUBLE"))
	{
		Ctrl("d_value"     ).SetXValue(Ctrl("VALUE_DOUBLE").GetXValue());
		Ctrl("d_value_text").SetXValue(Ctrl("VALUE_DOUBLE").GetCValue());
	}
	if (Ctrl("VALUE_DATE"))
	{
		Ctrl("d_value"     ).SetXValue(Ctrl("VALUE_DATE").GetXValue());
		Ctrl("d_value_text").SetXValue(Ctrl("VALUE_DATE").GetCValue());
	}
	if (Ctrl("VALUE_STRING"))
	{
		Ctrl("d_value"     ).SetXValue(Ctrl("VALUE_STRING").GetXValue());
		Ctrl("d_value_text").SetXValue(Ctrl("VALUE_STRING").GetXValue());
	}
	if (Ctrl("VALUE_ENUM"))
	{
	}
	if (Ctrl("VALUE_SCOMBO"))
	{
	}
	if (Ctrl("VALUE_FLOW"))
	{
	}
}

function OnLoadCustom()
{
	OnLoad();

	if (Ctrl("VALUE_BOOL"  )) Ctrl("VALUE_BOOL"  ).SetXValue(Ctrl("d_value").GetXValue());
	if (Ctrl("VALUE_INT"   )) Ctrl("VALUE_INT"   ).SetXValue(Ctrl("d_value").GetXValue());
	if (Ctrl("VALUE_DOUBLE")) Ctrl("VALUE_DOUBLE").SetXValue(Ctrl("d_value").GetXValue());
	if (Ctrl("VALUE_DATE"  )) Ctrl("VALUE_DATE"  ).SetXValue(Ctrl("d_value").GetXValue());
	if (Ctrl("VALUE_STRING")) Ctrl("VALUE_STRING").SetXValue(Ctrl("d_value").GetXValue());

	if (Ctrl("VALUE_ENUM"))
	{
	}
	if (Ctrl("VALUE_SCOMBO")) Ctrl("VALUE_SCOMBO").SetXValue(Ctrl("d_value_text").GetXValue());
	if (Ctrl("VALUE_FLOW")) Ctrl("VALUE_FLOW").SetXValue(Ctrl("d_value_text").GetXValue());
}              


function CallFlow()
{                                                                                                            
	var data=new NomadXML("DATA");
	data.SetAttr("value",Ctrl("d_value").GetXValue());
	data.SetAttr("text",Ctrl("d_value_text").GetXValue());

	openNewFlowWait(Ctrl("d_type_ext").GetXValue().split(":")[0], Ctrl("d_type_ext").GetXValue().split(":")[1], data.ToString(), new objFlowreturn(), "M");
}

function CallCombo()
{                                                                                                            
	var data=new NomadXML("DATA");
	data.SetAttr("value",Ctrl("d_value").GetXValue());
	data.SetAttr("text",Ctrl("d_value_text").GetXValue()); 
	data.SetAttr("RESOURCE",Ctrl("d_type_ext").GetXValue());

	openNewFlowWait("Nomad.Base.SuperCombo.guia.flow", "HELP", data.ToString(), new objFlowreturn(), "M");
}

function objFlowreturn()
{
	this.processResult = function(objXML)
	{                    
		objXML=new NomadXML(objXML);

		Ctrl("d_value").SetXValue(objXML.GetAttr("value"));
		Ctrl("d_value_text").SetXValue(objXML.GetAttr("text"));  

		//Actualizo la Pantalla		
		if (Ctrl("VALUE_SCOMBO")) Ctrl("VALUE_SCOMBO").SetXValue(objXML.GetAttr("text"));
		if (Ctrl("VALUE_FLOW")) Ctrl("VALUE_FLOW").SetXValue(objXML.GetAttr("text"));
	}
}

